INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES
(6, 1, '07', '손익계산서 vs 대차대조표', '문서에서 손익계산서와 대차대조표의 차이로 올바른 것은?', '손익계산서: 특정 시점의 스냅샷, 대차대조표: 기간의 흐름', '손익계산서: 기간의 흐름, 대차대조표: 특정 시점의 스냅샷', '둘 다 기간의 흐름을 나타냄', '둘 다 특정 시점의 스냅샷을 나타냄', 2, '문서에서 손익계산서가 기간의 흐름이라면 대차대조표는 특정 시점의 스냅샷이라고 설명합니다.'),
(6, 2, '07', '손익계산서 구조', '문서의 손익계산서 flowchart에서 영업이익(Operating Profit) 다음으로 이어지는 항목은?', '법인세', '매출총이익', '영업외수익/비용(이자, 환차익 등)', '당기순이익', 3, '문서 flowchart에서 영업이익 → 영업외수익/비용(이자, 환차익 등) → 세전이익(EBT) → 법인세 → 당기순이익 순으로 이어집니다.'),
(6, 3, '07', '영업이익률 공식', '문서에서 영업이익률의 공식으로 제시된 것은?', '영업이익 / 자산 × 100', '영업이익 / 매출액 × 100', '순이익 / 매출액 × 100', '영업이익 / 자본 × 100', 2, '문서 지표 표에서 영업이익률 = 영업이익 / 매출액 × 100으로 정의되며, 본업의 수익성을 나타냅니다.'),
(6, 4, '07', '매출 성장률 공식', '문서에서 매출 성장률의 공식은?', '(금기-전기) / 금기 × 100', '(전기-금기) / 전기 × 100', '(금기-전기) / 전기 × 100', '금기 / 전기 × 100', 3, '문서 지표 표에서 매출 성장률 = (금기-전기) / 전기 × 100으로 정의되며, 외형 성장 속도를 나타냅니다.'),
(6, 5, '07', '손익계산서 확인 항목', '문서에서 손익계산서 확인 항목 중 판관비율(판매비와관리비/매출액)을 통해 확인하는 것은?', '원가 경쟁력, 가격 결정력', '인건비·마케팅비·관리비 부담', '본업의 수익성, 경쟁력', '시장 성장과 점유율', 2, '문서에서 판관비율은 인건비·마케팅비·관리비 부담을 확인하는 항목으로 제시됩니다.'),
(6, 6, '07', '순이익 vs 영업이익', '문서에서 순이익이 영업이익보다 클 때 주의해야 하는 이유는?', '환율 영향이 과도하게 반영된 것일 수 있기 때문', '일회성 자산 매각 등 비경상 이익이 있을 수 있기 때문', '영업이익이 과소 계상된 것일 수 있기 때문', '세금 부담이 줄어든 것일 수 있기 때문', 2, '문서에서 순이익이 영업이익보다 크면 일회성 자산 매각 등 비경상 이익이 있을 수 있어 주의가 필요하다고 설명합니다.'),
(6, 7, '07', '손익계산서 주의 흐름', '문서에서 매출은 증가하지만 영업이익률이 하락하는 상황의 가능한 해석은?', '자산 매각, 투자수익 등 비경상 이익 가능성', '이자비용, 외환손실, 일회성 손실', '가격 경쟁, 원가 상승, 마케팅비 증가', '고정비 부담 감소, 경영 효율성 개선', 3, '문서 주의 흐름 표에서 매출은 증가하지만 영업이익률 하락의 가능한 해석은 가격 경쟁, 원가 상승, 마케팅비 증가입니다.'),
(6, 8, '07', '이익 개념', '문서의 피자가게 예시에서 이익(Profit)을 계산하는 공식은?', '매출액 - 재료비만', '매출액 - (재료비 + 임대료 + 인건비)', '매출액 ÷ 판매 수량', '매출액 - 임대료만', 2, '문서 피자가게 예시에서 이익 = 매출액(100,000원) - 재료비+임대료+인건비(70,000원) = 30,000원으로 설명됩니다.'),
(6, 9, '07', '흑자·적자 유래', '문서에서 흑자·적자라는 용어의 유래로 설명한 것은?', '주식시장에서 상승은 빨간색, 하락은 파란색으로 표시한 데서 비롯', '옛날 장부에서 이익은 검은 잉크(黑), 손실은 빨간 잉크(赤)로 기록한 데서 비롯', '회계법인에서 이익은 굵은 글씨, 손실은 얇은 글씨로 구분한 데서 비롯', '국세청 신고서에서 흑색·적색 도장을 사용한 데서 비롯', 2, '문서에서 흑자·적자의 유래는 옛날 장부에서 이익은 검은 잉크(黑), 손실은 빨간 잉크(赤)로 기록한 데서 비롯된다고 설명합니다.'),
(6, 10, '07', '이익의 3단계', '문서의 재무제표 이익 3단계에서 영업이익이 나타내는 것은?', '제품 자체가 얼마나 남기나', '본업으로 얼마나 버나', '최종적으로 주주에게 남는 이익', '외부 투자로 얼마나 버나', 2, '문서 이익의 3단계에서 영업이익(200억)은 본업으로 얼마나 버나를 나타내며, 매출총이익에서 판관비를 뺀 수치입니다.'),
(6, 11, '07', '대차대조표 핵심 항등식', '문서에서 제시한 대차대조표의 핵심 항등식은?', '자산 = 자본 - 부채', '부채 = 자산 + 자본', '자산 = 부채 + 자본', '자본 = 부채 - 자산', 3, '문서에서 대차대조표의 핵심 항등식은 자산(Assets) = 부채(Liabilities) + 자본(Equity)로 제시됩니다.'),
(6, 12, '07', '대차대조표 유동자산', '문서의 대차대조표 구조에서 유동자산에 속하는 항목은?', '특허·영업권 (무형자산)', '공장·설비 (유형자산)', '현금및현금성자산·매출채권·재고자산', '장기차입금·사채', 3, '문서 대차대조표 block-beta 다이어그램에서 유동자산에는 현금및현금성자산, 매출채권, 재고자산이 포함됩니다.'),
(6, 13, '07', '부채비율 해석 기준', '문서에서 부채비율(부채/자본×100)의 해석 기준으로 올바른 것은?', '50% 이하 안정, 100% 이상 주의', '100% 이하 안정, 200% 이상 주의', '150% 이하 안정, 300% 이상 주의', '200% 이하 안정, 400% 이상 주의', 2, '문서 주요 안전성 지표 표에서 부채비율의 해석 기준은 100% 이하 안정, 200% 이상 주의로 제시됩니다.'),
(6, 14, '07', '유동비율 해석 기준', '문서에서 유동비율(유동자산/유동부채×100)의 양호 기준은?', '100% 이상', '120% 이상', '150% 이상', '200% 이상', 3, '문서 주요 안전성 지표 표에서 유동비율은 150% 이상이면 양호로 해석됩니다.'),
(6, 15, '07', '이자보상배율 위험 기준', '문서에서 이자보상배율(영업이익/이자비용)이 위험한 수준으로 제시된 것은?', '0.5배 이하', '1배 이하', '2배 이하', '3배 이하', 2, '문서 주요 안전성 지표 표에서 이자보상배율은 1배 이하일 때 위험으로 해석됩니다.'),
(6, 16, '07', '대차대조표 확인 - 매출채권', '문서에서 매출채권을 확인하는 투자 관점의 이유는?', '경기 둔화와 투자 기회에 버틸 여력 확인', '수요 둔화, 가격 인하, 평가손실 위험 확인', '팔았지만 아직 돈을 못 받은 매출 가능성 확인', '유동성 위험, 차환 리스크 확인', 3, '문서 대차대조표 확인 항목 표에서 매출채권의 투자 관점은 팔았지만 아직 돈을 못 받은 매출 가능성 확인입니다.'),
(6, 17, '07', '대차대조표 분석 순서', '문서의 대차대조표 분석 순서에서 두 번째 단계는?', '유동자산과 유동부채를 비교해 단기 지급능력을 본다', '자산 증가가 부채 증가 때문인지, 이익 누적 때문인지 나눠 본다', '매출채권·재고자산이 매출보다 빠르게 늘면 이익의 질을 의심한다', '부채비율과 이자보상배율로 차입 부담을 확인한다', 2, '문서 대차대조표 분석 순서에서 2번째 단계는 자산 증가가 부채 증가 때문인지, 이익 누적 때문인지 나눠 보는 것입니다.'),
(6, 18, '07', '손익·대차 연결 읽기', '문서에서 손익계산서의 영업이익 개선 시 대차대조표에서 확인할 것은?', '매출채권도 같이 급증했는지', '재고자산 평가손실이나 원재료 부담', '현금과 이익잉여금 증가로 이어졌는지', '차입금과 부채비율이 상승했는지', 3, '문서 손익계산서·대차대조표 연결 표에서 영업이익 개선 시 현금과 이익잉여금 증가로 이어졌는지 확인해야 합니다.'),
(6, 19, '07', '유동부채 정의', '문서에서 유동부채의 정의와 예시로 올바른 것은?', '1년 넘어 갚아도 되는 빚 (장기차입금, 회사채)', '1년 안에 갚아야 하는 빚 (단기차입금, 외상매입금)', '이자 부담 없이 빌린 빚', '주주에게 반환해야 할 의무', 2, '문서 부채의 두 가지 종류 표에서 유동부채는 1년 안에 갚아야 하는 빚으로, 단기차입금, 외상매입금(매입채무)이 해당됩니다.'),
(6, 20, '07', '좋은 부채 vs 나쁜 부채', '문서에서 좋은 부채(레버리지 효과)에 해당하는 상황은?', '부채가 너무 많아 이자도 못 냄', '부채로 공장 짓고 매출·이익이 증가', '부채로 자사주를 매입', '부채로 배당을 지급', 2, '문서 부채 해석 표에서 부채로 공장 짓고 매출·이익이 증가하는 경우를 좋은 부채(레버리지 효과)라고 설명합니다.'),
(6, 21, '07', 'ROE 정의', '문서에서 ROE(자기자본이익률)가 나타내는 핵심 질문은?', '회사가 갖고 있는 모든 자산으로 얼마나 벌었나', '내가 직접 투자한 내 돈으로 얼마나 벌었나', '투자한 돈 전체(내 돈+빌린 돈)로 얼마나 벌었나', '이 투자가 수익이 났나', 2, '문서에서 ROE는 내가 직접 투자한 내 돈으로 얼마나 벌었나를 나타내며, 당기순이익 ÷ 자기자본(평균) × 100으로 계산합니다.'),
(6, 22, '07', 'ROE 공식', '문서에서 ROE의 계산 공식은?', '당기순이익 ÷ 총자산(평균) × 100', '(순이익 + 이자비용) ÷ 총투자액 × 100', '당기순이익 ÷ 자기자본(평균) × 100', '영업이익 ÷ 자기자본 × 100', 3, '문서에서 ROE(%) = 당기순이익 ÷ 자기자본(평균) × 100으로 계산하며, 워런 버핏이 중요시하는 지표 중 하나입니다.'),
(6, 23, '07', 'ROA 정의', '문서에서 ROA(총자산이익률)가 나타내는 핵심 질문은?', '주주 돈으로 얼마나 벌었나', '투자 비용 대비 얼마나 벌었나', '자산 전체를 얼마나 효율적으로 쓰나', '부채를 제외한 순자산 대비 이익', 3, '문서에서 ROA는 자산 전체를 얼마나 효율적으로 쓰나를 나타내며, 당기순이익 ÷ 총자산(평균) × 100으로 계산합니다.'),
(6, 24, '07', 'ROE와 ROA 관계', '문서에서 ROE와 ROA의 관계식으로 제시된 것은?', 'ROE = ROA ÷ (총자산 / 자기자본)', 'ROE = ROA × (총자산 / 자기자본)', 'ROE = ROA + 부채비율/100', 'ROE = ROA - (부채 / 자본)', 2, '문서에서 ROE = ROA × (총자산 / 자기자본) = ROA × (1 + 부채비율/100)으로, 부채가 많을수록 ROA보다 ROE가 높게 나타납니다.'),
(6, 25, '07', 'ROE 좋은 수준', '문서에서 ROE의 좋은 수준으로 제시된 기준은?', '5% 이상', '10% 이상', '15% 이상', '20% 이상', 2, '문서 세 지표 비교 표에서 ROE의 좋은 수준은 10% 이상으로 제시됩니다(보통 10% 이상이면 우량, 15~20% 이상이면 탁월).'),
(6, 26, '07', 'DART API - 사업보고서 코드', '문서에서 DART API의 사업보고서(Annual Report)에 해당하는 reprt_code 값은?', '11013', '11012', '11014', '11011', 4, '문서 보고서 코드 표에서 11011이 사업보고서에 해당합니다(11013: 1분기보고서, 11012: 반기보고서, 11014: 3분기보고서).'),
(6, 27, '07', 'DART API - 연결재무제표', '문서에서 DART API의 fs_div 파라미터 중 연결재무제표를 의미하는 값은?', 'OFS', 'CFS', 'IFS', 'SFS', 2, '문서 주요 DART 파라미터 표에서 fs_div의 CFS는 연결재무제표를, OFS는 별도 재무제표를 의미합니다.'),
(6, 28, '07', 'ACCOUNT_ALIASES - revenue', '문서의 ACCOUNT_ALIASES에서 revenue(매출) 계정의 alias에 해당하지 않는 것은?', '매출액', '영업수익', '영업이익', '수익(매출액)', 3, '문서 ACCOUNT_ALIASES에서 revenue의 alias는 매출액, 수익(매출액), 영업수익, 매출 등이며, 영업이익은 operating_income에 해당합니다.'),
(6, 29, '07', '재무비율 - 활동성 지표', '문서에서 재무비율 분석의 활동성 축에 해당하는 지표는?', '매출 성장률, 영업이익 성장률', '영업이익률, 순이익률, ROE, ROA', '자산회전율, 재고자산 회전율, 매출채권 회전율', '부채비율, 유동비율, 차입금 의존도', 3, '문서 분석 축 표에서 활동성 지표는 자산회전율, 재고자산 회전율, 매출채권 회전율입니다.'),
